def get_hip_version():
    hipconfig = "/opt/rocm/bin/hipconfig"
    if not os.path.isfile(hipconfig):
        for var in ("ROCM_PATH", "ROCM_HOME", "HIP_PATH"):
            candidate = os.path.join(os.environ.get(var, ""), "bin", "hipconfig")
            if candidate and os.path.isfile(candidate):
                hipconfig = candidate
                break
        else:
            hipconfig = shutil.which("hipconfig") or hipconfig
    version = subprocess.run(
        [hipconfig, "--version"], capture_output=True, text=True
    )
    stdout = (version.stdout or "").strip()
    if not stdout:
        raise RuntimeError(
            f"hipconfig at {hipconfig!r} produced no output (rc={version.returncode}): "
            f"{version.stderr!r}"
        )
    return parse(stdout.split()[-1].rstrip("-").replace("-", "+"))
